26_reduce_product_of_inverses:
```cpp
#pragma once
#include <vector>
#include <cstddef>
#include <cmath>
#include <limits>
#include <omp.h>

/* Return the product of the vector x with every odd indexed element inverted.
   i.e. x_0 * 1/x_1 * x_2 * 1/x_3 * x_4 ...
   Example:
   input: [4, 2, 10, 4, 5]
   output: 25
*/
double productWithInverses(std::vector<double> const& x)
{
    // Handle empty vector – the product of no factors is 1.
    if (x.empty()) return 1.0;

    double product = 1.0;

    // Parallel reduction with OpenMP.
    // Each thread works on a chunk of the array, accumulating a local
    // product in a thread‑private variable.  The final reduction combines
    // these local products into the global result.
    #pragma omp parallel
    {
        double local = 1.0;
        #pragma omp for nowait
        for (std::size_t i = 0; i < x.size(); ++i) {
            double val = (i & 1u) ? 1.0 / x[i] : x[i];
            local *= val;
        }
        #pragma omp atomic
        product *= local;
    }

    return product;
}
