/* Count, for each lowercase alphabet letter, how many strings in `s`
   start with that letter. The result is stored in `bins`.
   Parallelised with OpenMP for maximum throughput on 8‑thread CPUs.
*/
void firstLetterCounts(std::vector<std::string> const& s,
                       std::array<std::size_t, 26>& bins)
{
    // Zero the output array once in a thread‑safe way
    std::fill(bins.begin(), bins.end(), 0);

    // Each thread keeps a private accumulator; 26 integers per thread
    const int n_threads = omp_get_max_threads();
    std::vector<std::array<std::size_t, 26>> local(n_threads);
    for (int t = 0; t < n_threads; ++t)
        local[t].fill(0);

#pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        auto& private_bins = local[tid];

        // Work division: static schedule is the fastest for simple loops
#pragma omp for schedule(static)
        for (std::size_t i = 0; i < s.size(); ++i) {
            const char c = s[i][0];               // first character
            const std::size_t idx = static_cast<std::size_t>(c - 'a');
            private_bins[idx] += 1;
        }
    }

