```cpp
#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

struct COOElement {
    size_t row;
    size_t column;
    double value;
};

/*  y = alpha * A * x + beta * y
 *  A  : sparse matrix in COO format (size M × N)
 *  x,y: vectors of length N (y also has length M)
 *
 *  The implementation keeps the exact semantics of the original
 *  reference code but uses OpenMP to parallelise the work.
 */
inline void spmv(double alpha,
                 const std::vector<COOElement> &A,
                 const std::vector<double> &x,
                 double beta,
                 std::vector<double> &y,
                 size_t M,
                 size_t N)
{
    const size_t ylen = y.size();
    const size_t xlen = x.size();

    // Scale the output vector y by beta in parallel
    #pragma omp parallel for schedule(static)
    for (ptrdiff_t i = 0; i < static_cast<ptrdiff_t>(ylen); ++i)
        y[i] *= beta;

    // Perform the sparse matrix‑vector product in parallel
    // with an atomic update to avoid write conflicts.
    #pragma omp parallel for schedule(static)
    for (ptrdiff_t k = 0; k < static_cast<ptrdiff_t>(A.size()); ++k) {
        const COOElement &e = A[static_cast<size_t>(k)];
        if (e.row < M && e.column < xlen) {
            double add = alpha * e.value * x[e.column];
            // Writing to y[e.row] may be contended; use atomic
            #pragma omp atomic
            y[e.row] += add;
        }
    }
}
