#pragma once
#include <vector>
#include <algorithm>
#include <cstddef>
#include <omp.h>

/* Compute the highest node degree in the undirected graph.
   A is an N×N adjacency matrix stored in row-major order.
   The matrix is symmetric and contains only 0/1 entries.
   The algorithm sums each row and keeps the maximum sum.
*/
inline int maxDegree(const std::vector<int>& A, std::size_t N) {
    int highestDegree = 0;

    // Parallelize the outer loop.  The inner sum is small, so we can keep
    // it in the thread's register.  `reduction(max:highestDegree)` guarantees
    // the correct maximum across all threads.
#pragma omp parallel for schedule(static) reduction(max:highestDegree)
    for (int i = 0; i < static_cast<int>(N); ++i) {
        int degree = 0;
        const int* row = &A[i * N];          // pointer to the beginning of the row
        // Use simple unrolling for a bit of extra speed
        int j = 0;
        for (; j <= static_cast<int>(N) - 8; j += 8) {
            degree += row[j]   + row[j+1] + row[j+2] + row[j+3]
                    + row[j+4] + row[j+5] + row[j+6] + row[j+7];
        }
        for (; j < static_cast<int>(N); ++j) {
            degree += row[j];
        }
        if (degree > highestDegree) highestDegree = degree;
    }
    return highestDegree;
}
