 *           {x=1.5, y=-1}, {x=3, y=-7}, {x=0.1, y=2}]
 *   output: [3, 1, 0, 2]
 */
void countQuadrants(std::vector<Point> const& points, std::array<size_t, 4> &bins) {
   /* Ensure the destination array is zero‑initialized */
   bins[0] = bins[1] = bins[2] = bins[3] = 0;

