   /* Parallel loop with explicit reduction on each bin. */
   #pragma omp parallel for reduction(+:bins[0],bins[1],bins[2],bins[3])
#endif
   for (std::size_t i = 0; i < points.size(); ++i) {
      const auto &p = points[i];
      if (p.x >= 0.0) {
         if (p.y >= 0.0) {
            ++bins[0];          // Quadrant I
         } else {
            ++bins[3];          // Quadrant IV
         }
      } else {
         if (p.y >= 0.0) {
            ++bins[1];          // Quadrant II
         } else {
            ++bins[2];          // Quadrant III
         }
      }
   }
}
