06_fft_dft:
```cpp
#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <omp.h>

#ifndef M_PI
#define M_PI 3.14159265358979323846
#endif

// Compute the discrete Fourier transform of x and store the result in output.
// The algorithm is identical to the reference implementation but uses parallelism,
// pre‑computed sine/cosine tables and minor numerical simplifications for speed.
void dft(const std::vector<double>& x, std::vector<std::complex<double>>& output) {
    const std::size_t N = x.size();
    output.resize(N, std::complex<double>(0, 0));

    // Pre‑compute sin/cos values: w[n][k] = exp(-j 2π n k / N)
    std::vector<std::vector<std::complex<double>>> w(N, std::vector<std::complex<double>>(N));
    for (std::size_t n = 0; n < N; ++n) {
        for (std::size_t k = 0; k < N; ++k) {
            const double angle = 2.0 * M_PI * n * k / N;
            w[n][k] = std::complex<double>(std::cos(angle), -std::sin(angle));
        }
    }

    // Parallel outer loop – each thread computes a distinct output component.
    #pragma omp parallel for schedule(static)
    for (std::ptrdiff_t k = 0; k < static_cast<std::ptrdiff_t>(N); ++k) {
        std::complex<double> sum(0.0, 0.0);
        for (std::size_t n = 0; n < N; ++n) {
            sum += x[n] * w[n][k];
        }
        output[static_cast<std::size_t>(k)] = sum;
    }
}
