/*
 * Count the number of doubles in the vector `x` whose fractional part lies in
 * the four quartiles:
 *   [0, 0.25) , [0.25, 0.5) , [0.5, 0.75) , [0.75, 1)
 *
 * The counts are written to `bins` (size 4). The routine is thread‑safe and
 * preserves the original semantics.
 */
inline void countQuartiles(std::vector<double> const& x, std::array<size_t, 4>& bins)
{
    // Initialise bins; we rely on the reduction clause to aggregate the
    // partial results from all threads.
    bins[0] = bins[1] = bins[2] = bins[3] = 0;

    // Parallel accumulation with OpenMP.  Each thread keeps a private copy
    // of the four counters and they are summed up automatically at the end.
    #pragma omp parallel for reduction(+:bins[0], bins[1], bins[2], bins[3])
    for (size_t i = 0; i < x.size(); ++i)
    {
        // Extract fractional part reliably for positive and negative values.
        double val   = x[i];
        double floor = std::floor(val);
        double frac  = val - floor;

        // Negative fractions correspond to positive ones because the
        // fractional part of a negative number is in (0,1) as well.
        if (frac < 0.25)      ++bins[0];
        else if (frac < 0.5)  ++bins[1];
        else if (frac < 0.75) ++bins[2];
        else                  ++bins[3];
    }
}
