    std::fill(bins.begin(), bins.end(), 0);

    // Determine number of threads
    int n_threads = omp_get_max_threads();

    // Per‑thread local bins
    std::vector<std::array<size_t, 256>> local_bins(n_threads);
    for (auto &lb : local_bins)
        std::fill(lb.begin(), lb.end(), 0);

    const int* img = image.data();
    size_t sz = image.size();

    #pragma omp parallel
