#pragma once
#include <vector>
#include <stack>
#include <cstddef>
#include <algorithm>
#include <atomic>
#include <omp.h>

int largestComponent(const std::vector<int> &A, std::size_t N) {
    // Visited array as atomic flags to allow lock‑free concurrent writes
    std::vector<std::atomic<bool>> visited(N);
    for (auto &b : visited) b.store(false, std::memory_order_relaxed);

    int maxCount = 0;

    // Each thread keeps its own local maximum to avoid contention
    std::vector<int> localMax(omp_get_max_threads(), 0);

#pragma omp parallel
    {
        int threadId = omp_get_thread_num();
        std::stack<int> st;
        int localMaxCount = 0;

        // Iterate over all vertices; each thread checks a slice of the range.
        // The `if (!visited[i].exchange(true))` idiom guarantees that only one
        // thread will start a DFS from an undiscovered vertex.
        for (std::size_t i = 0; i < N; ++i) {
            if (!visited[i].exchange(true, std::memory_order_acq_rel)) {
                st.push(static_cast<int>(i));
                int count = 0;
                while (!st.empty()) {
                    int v = st.top(); st.pop();
                    ++count;
                    std::size_t base = v * N;
                    for (std::size_t j = 0; j < N; ++j) {
                        if (A[base + j] == 1 &&
                            !visited[j].exchange(true, std::memory_order_acq_rel)) {
                            st.push(static_cast<int>(j));
                        }
                    }
                }
                localMaxCount = std::max(localMaxCount, count);
            }
        }
        localMax[threadId] = localMaxCount;
    }

    // Reduce local maxima to obtain the global maximum
    for (int v : localMax) maxCount = std::max(maxCount, v);
    return maxCount;
}
