    #pragma omp parallel for schedule(static)
    for (int i = 0; i < static_cast<int>(bins.size()); ++i)
        bins[i] = 0;

    // Parallel counting using an array reduction (GCC‑supported)
    #pragma omp parallel for schedule(static) reduction(+:bins[:10])
    for (std::size_t i = 0; i < x.size(); ++i) {
        // The original code used implicit truncation via size_t conversion.
        const std::size_t bin = static_cast<std::size_t>(x[i] / 10.0);
