/*
 * Replace the i‑th element of the vector `x` with the minimum value from
 * indices 0 through i.
 *
 * The implementation uses a conservative parallel prefix‑minimum
 * algorithm that is safe for use with `gcc -O2 -fopenmp`.
 * It preserves the exact semantics of the original function.
 */
inline void partialMinimums(std::vector<float> &x) {
    if (x.empty())
        return;

    constexpr size_t CHUNK = 1024;               // tune for cache friendliness
    const size_t n = x.size();

    // First compute local minima for each chunk in parallel
    std::vector<float> chunk_min((n + CHUNK - 1) / CHUNK);
#pragma omp parallel for schedule(static)
    for (size_t i = 0; i < chunk_min.size(); ++i) {
        size_t start = i * CHUNK;
        size_t end   = std::min(start + CHUNK, n);
        float local_min = std::numeric_limits<float>::max();
        for (size_t j = start; j < end; ++j)
            if (x[j] < local_min)
                local_min = x[j];
        chunk_min[i] = local_min;
    }

    // Compute prefix minima for the chunk minima sequentially
    std::vector<float> prefix_min(chunk_min.size());
    float current = std::numeric_limits<float>::max();
    for (size_t i = 0; i < chunk_min.size(); ++i) {
        current = std::min(current, chunk_min[i]);
        prefix_min[i] = current;
    }

    // Propagate the prefix minima back to the original array in parallel
#pragma omp parallel for schedule(static)
    for (size_t i = 0; i < chunk_min.size(); ++i) {
        size_t start = i * CHUNK;
        size_t end   = std::min(start + CHUNK, n);
        float left_min = (i == 0) ? std::numeric_limits<float>::max() : prefix_min[i - 1];

        // Update each element in this chunk
        for (size_t j = start; j < end; ++j) {
            // The running minimum over this chunk
            if (j == start)
                left_min = std::min(left_min, x[j]);
            else
                left_min = std::min(left_min, x[j]);

            x[j] = left_min;
        }
    }
}
