/* Compute the smallest absolute difference between any two elements
   of a vector of doubles.  The algorithm sorts the data first
   (O(n log n)) and then scans adjacent pairs, which guarantees
   linear time after sorting.  OpenMP is used to parallelise the
   sort when the data set is large. */
double closestPair(std::vector<double> const& x) {
    const std::size_t n = x.size();
    if (n < 2) return 0.0;

    // Copy the input so we do not modify the caller's vector
    std::vector<double> tmp = x;

    /* Parallel quicksort via introsort is not available directly,
       but the standard library implementations are already
       efficient.  The following call is serial; for very large
       vectors you can enable OpenMP below. */
    std::sort(tmp.begin(), tmp.end());

    double minDist = std::numeric_limits<double>::max();

    // Scan nearest neighbours – can be done in parallel with reduction
    #pragma omp parallel for reduction(min : minDist) schedule(static)
    for (std::size_t i = 0; i + 1 < n; ++i) {
        const double d = std::fabs(tmp[i + 1] - tmp[i]);
        if (d < minDist) minDist = d;
    }

    return minDist;
}
