#pragma once
#include <vector>
#include <limits>
#include <cstddef>

/* Return the length of the shortest path from source to dest in the undirected graph
   defined by the adjacency matrix A (row‑major). The graph is guaranteed to be
   connected. */
int shortestPathLength(std::vector<int> const& A, size_t N, int source, int dest)
{
    if (source == dest) return 0;

    // Two queues for bidirectional BFS
    std::vector<int> qA(N), qB(N);
    size_t headA = 0, tailA = 0, headB = 0, tailB = 0;

    // One array for visitation status: 0 = unvisited,
    // 1 = visited from A side, 2 = visited from B side
    std::vector<unsigned char> mark(N, 0);

    qA[tailA++] = source;
    mark[source] = 1;

    qB[tailB++] = dest;
    mark[dest] = 2;

    int distA = 0, distB = 0;

    while (headA < tailA && headB < tailB)
    {
        // Expand the smaller frontier first (heuristic)
        if (tailA - headA <= tailB - headB)
        {
            size_t current = qA[headA++];
            ++distA;

            size_t base = current * N;
            for (size_t i = 0; i < N; ++i)
            {
                if (!A[base + i]) continue;
                if (mark[i] == 1) continue;
                if (mark[i] == 2) return distA + distB;
                mark[i] = 1;
                qA[tailA++] = static_cast<int>(i);
            }
        }
        else
        {
            size_t current = qB[headB++];
            ++distB;

            size_t base = current * N;
            for (size_t i = 0; i < N; ++i)
            {
                if (!A[base + i]) continue;
                if (mark[i] == 2) continue;
                if (mark[i] == 1) return distA + distB;
                mark[i] = 2;
                qB[tailB++] = static_cast<int>(i);
            }
        }
    }

    // Fallback: should never happen for a connected graph
    return std::numeric_limits<int>::max();
}
