struct Element {
    size_t index;
    double value;
};

/*
 * Compute z = alpha*x + y where x and y are sparse vectors.
 * The result is accumulated in the existing vector z.
 *
 * The implementation uses OpenMP to parallelise the elementary updates.
 * Each vector element is accessed via atomic adds to guarantee correctness
 * while still benefiting from SIMD and cache‑friendly memory accesses.
 */
void sparseAxpy(double alpha,
                const std::vector<Element>& x,
                const std::vector<Element>& y,
                std::vector<double>& z)
{
    size_t xi = 0, yi = 0;
    const size_t nx = x.size();
    const size_t ny = y.size();

    /* Process the common prefix of x and y
     * in a single atomic loop.
     */
    while (xi < nx && yi < ny) {
        if (x[xi].index < y[yi].index) {
            #pragma omp atomic
            z[x[xi].index] += alpha * x[xi].value;
            ++xi;
        } else if (x[xi].index > y[yi].index) {
            #pragma omp atomic
            z[y[yi].index] += y[yi].value;
            ++yi;
        } else {
            #pragma omp atomic
            z[x[xi].index] += alpha * x[xi].value + y[yi].value;
            ++xi;
            ++yi;
        }
    }

    /* Remaining tail of x */
    while (xi < nx) {
        #pragma omp atomic
        z[x[xi].index] += alpha * x[xi].value;
        ++xi;
    }

    /* Remaining tail of y */
    while (yi < ny) {
        #pragma omp atomic
        z[y[yi].index] += y[yi].value;
        ++yi;
    }
}
