#pragma once
#include <vector>
#include <cstdint>
#include <omp.h>

/*
   Compute the inclusive prefix sum of the vector `x` into `output`.
   Using a parallel scan that works correctly on all architectures
   and preserves the original behaviour of std::inclusive_scan.
   The number of threads (up to 8 on the target machine) is set
   by the OpenMP environment.
*/
inline void prefixSum(std::vector<int64_t> const& x,
                      std::vector<int64_t> &output)
{
    const std::size_t n = x.size();
    if (n == 0) return;

    output.resize(n);
    const int maxThreads = omp_get_max_threads();
    const int chunk = (n + maxThreads - 1) / maxThreads;   // ceil

    // 1) Each thread computes the inclusive scan of its chunk and
    //    stores the local sum of the entire chunk.
    std::vector<int64_t> localSums(maxThreads, 0);
    #pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        const std::size_t start = tid * static_cast<std::size_t>(chunk);
        const std::size_t end   = std::min(start + static_cast<std::size_t>(chunk), n);

        if (start < end) {
            // Inclusive scan for the thread's slice
            int64_t sum = 0;
            for (std::size_t i = start; i < end; ++i) {
                sum += x[i];
                output[i] = sum;
            }
            localSums[tid] = sum;   // sum of the whole chunk
        }
    }

    // 2) Compute exclusive prefix of local sums (offset for each thread)
    std::vector<int64_t> offsets(maxThreads, 0);
    int64_t acc = 0;
    for (int t = 0; t < maxThreads; ++t) {
        offsets[t] = acc;
        acc += localSums[t];
    }

    // 3) Add the offset to each thread's slice
    #pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        const std::size_t start = tid * static_cast<std::size_t>(chunk);
        const std::size_t end   = std::min(start + static_cast<std::size_t>(chunk), n);
        const int64_t off = offsets[tid];

        if (off != 0) {
            for (std::size_t i = start; i < end; ++i) {
                output[i] += off;
            }
        }
    }
}
