/*
 * Compute one iteration of a 3‑point 1‑D Jacobi stencil on `input`.
 * Each element of `input` is averaged with its two neighbors
 * and stored in the corresponding element of `output`.
 * A zero value is used when a neighbor lies outside the array.
 *
 * This implementation preserves the original behaviour while
 * exploiting cache friendliness and parallel execution.
 */
inline void jacobi1D(const std::vector<double> &input, std::vector<double> &output)
{
    const std::size_t N = input.size();
    if (N == 0) return;

    /* Ensure output has the same size as input */
    if (output.size() != N)
        output.resize(N);

    /* Local pointers for speed */
    const double *in  = input.data();
    double       *out = output.data();

    /* Bound check replacement: use contiguous arrays and explicit
     * handling of first and last elements outside the main loop. */
    out[0] = (in[0] + in[1]) / 3.0;                     // first element
    out[N-1] = (in[N-2] + in[N-1]) / 3.0;              // last element

    /* Parallel loop for interior points.
     * Static scheduling keeps work balanced on HLS core sets. */
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 1; i < N-1; ++i) {
        out[i] = (in[i-1] + in[i] + in[i+1]) / 3.0;
    }
}
