#pragma once
#include <vector>
#include <unordered_map>
#include <omp.h>

struct COOElement {
   size_t row, column;
   double value;
};

/* Compute the matrix multiplication Y = A * X.
   A: sparse MxK matrix in COO format.
   X: sparse KxN matrix in COO format.
   Y: dense MxN matrix in row-major order.
*/
void spmm(std::vector<COOElement> const& A,
          std::vector<COOElement> const& X,
          std::vector<double> &Y,
          size_t M, size_t K, size_t N)
{
   // 1. Build hash table of X by their row index.
   std::unordered_map<size_t, std::vector<std::pair<size_t, double>>> x_by_row;
   x_by_row.reserve(X.size());
   for (const auto& e : X) {
      x_by_row[e.row].emplace_back(e.column, e.value);
   }

   // 2. Prepare per‑thread local result buffers to avoid atomic writes.
   int nthreads = omp_get_max_threads();
   std::vector< std::vector<double> > localY(nthreads, std::vector<double>(M * N, 0.0));

   // 3. Parallel traversal of A. Each thread processes a contiguous chunk.
   #pragma omp parallel
   {
      int id = omp_get_thread_num();
      auto& local = localY[id];
      for (size_t i = 0; i < A.size(); ++i) {
         if (i % nthreads != id) continue;          // simple manual chunking for speed
         const auto& a = A[i];
         auto it = x_by_row.find(a.column);
         if (it == x_by_row.end()) continue;
         const auto& vec = it->second;
         size_t base = a.row * N;
         for (const auto& xv : vec) {
            local[base + xv.first] += a.value * xv.second;
         }
      }
   }

   // 4. Combine per‑thread results into Y.
   Y.assign(M * N, 0.0);
   for (int t = 0; t < nthreads; ++t) {
      const auto& lo = localY[t];
      for (size_t idx = 0; idx < M * N; ++idx) {
         Y[idx] += lo[idx];
      }
   }
}
