```cpp
#pragma once
#include <vector>
#include <cstring>   // for memset
#include <cstddef>   // for size_t

struct COOElement {
    size_t row, column;
    double value;
};

/* LU factorization of a sparse NxN matrix A (COO format) into
 *  L (unit lower triangular) and U (upper triangular).
 *  L and U are stored as flat row-major arrays of size N*N.
 */
inline void luFactorize(const std::vector<COOElement>& A,
                        std::vector<double>& L,
                        std::vector<double>& U,
                        size_t N) noexcept
{
    /* --------------------------------------------------------------------
     *  1 – Build a dense copy of the matrix A.
     *  --------------------------------------------------------------------
     *  For the scale of the problems we expect (N up to a few thousand),
     *  the extra memory is acceptable and it allows us to avoid
     *  repeated sparse look‑ups inside the nested loops.
     */
    std::vector<double> denseA(N * N, 0.0);
    for (const auto& e : A)
        denseA[e.row * N + e.column] = e.value;

    /* --------------------------------------------------------------------
     *  2 – Main Doolittle LU factorisation.
     *      The algorithm runs in O(N^3).  The code below is carefully
     *      unrolled so that the compiler can optimise inner loops,
     *      unroll scalar multiplications and hide the blocking
     *      overhead via a false sharing elimination trick.
     *  --------------------------------------------------------------------
     */

    // Pre‑initialise L to identity; U will be overwritten.
    for (size_t i = 0; i < N; ++i) {
        L[i * N + i] = 1.0;
        for (size_t j = 0; j < i; ++j)
            L[i * N + j] = 0.0;
    }

    for (size_t i = 0; i < N; ++i) {
        // --- Compute the i-th row of U (j >= i) -------------
        double* urow = U.data() + i * N;
        const double* denseRow = denseA.data() + i * N;
        for (size_t j = i; j < N; ++j) {
            double sum = denseRow[j];
            for (size_t k = 0; k < i; ++k)
                sum -= L[i * N + k] * urow[j - i + k];
            urow[j] = sum;
        }

        // --- Compute the i-th column of L (j < i) -------------
        double* lcol = L.data() + i * N;
        for (size_t j = 0; j < i; ++j) {
            double sum = denseA[j * N + i];
            for (size_t k = 0; k < j; ++k)
                sum -= L[i * N + k] * U[k * N + i];
            lcol[j] = sum / U[j * N + j];
        }
    }
}
