#pragma once
#include <vector>
#include <cmath>
#include <algorithm>
#include <omp.h>

struct COOElement {
   size_t row, column;
   double value;
};

/* Solve the sparse linear system Ax=b for x.
   A is a sparse NxN matrix in COO format. x and b are dense vectors with N elements.
   Example:

   input: A=[{0,0,1}, {0,1,1}, {1,1,-2}] b=[1,4]
   output: x=[3,-2]
*/
void solveLinearSystem(const std::vector<COOElement>& A,
                       const std::vector<double> &b,
                       std::vector<double> &x,
                       size_t N)
{
    // Allocate a flat dense matrix to improve cache usage
    std::vector<double> matrix(N * N, 0.0);
    std::vector<double> b_copy = b;

    // Fill the matrix with the values from A
    #pragma omp parallel for schedule(static)
    for (size_t idx = 0; idx < A.size(); ++idx) {
        const auto& e = A[idx];
        matrix[e.row * N + e.column] = e.value;
    }

    // Gaussian elimination with partial pivoting
    for (size_t i = 0; i < N; ++i) {
        // Find pivot row
        size_t maxRow = i;
        double maxVal = std::abs(matrix[i * N + i]);
        for (size_t k = i + 1; k < N; ++k) {
            double val = std::abs(matrix[k * N + i]);
            if (val > maxVal) {
                maxVal = val;
                maxRow = k;
            }
        }

        // Swap pivot row with current row (both matrix and RHS)
        if (maxRow != i) {
            #pragma omp parallel for schedule(static)
            for (size_t c = 0; c < N; ++c) {
                std::swap(matrix[maxRow * N + c], matrix[i * N + c]);
            }
            std::swap(b_copy[maxRow], b_copy[i]);
        }

        // Eliminate the column below the pivot
        double pivot = matrix[i * N + i];
        if (pivot == 0.0) continue; // singular matrix – keep behaviour

        #pragma omp parallel for schedule(static)
        for (size_t k = i + 1; k < N; ++k) {
            double factor = -matrix[k * N + i] / pivot;
            // Update the rest of the row
            for (size_t j = i; j < N; ++j) {
                if (j == i) {
                    matrix[k * N + j] = 0.0;
                } else {
                    matrix[k * N + j] += factor * matrix[i * N + j];
                }
            }
            b_copy[k] += factor * b_copy[i];
        }
    }

    // Back substitution
    x.resize(N);
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        double sum = b_copy[i];
        for (int j = i + 1; j < static_cast<int>(N); ++j) {
            sum -= matrix[i * N + j] * x[j];
        }
        x[i] = sum / matrix[i * N + i];
    }
}
