/* Set every cell's value to 1 if it has exactly one neighbor that's a 1.
   Otherwise set it to 0.  The grid is stored row‑major in a flat vector
   of length N*N.  The function is fully thread‑safe because each
   element of `output` is written exactly once and reads from `input`
   never depend on an output element. */
inline void cellsXOR(std::vector<int> const& input,
                     std::vector<int> &output,
                     size_t N)
{
    /* Parallelise over rows: each thread handles a contiguous block of
       rows.  All neighbouring reads are within the same `input` vector,
       so there is no data race.  We use loop collapse to give the
       compiler maximum freedom for vectorisation. */
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i) {
        size_t rowTop = (i > 0)      ? input[(i - 1) * N]       : 0;
        size_t rowBot = (i + 1 < N)  ? input[(i + 1) * N]       : 0;
        size_t base   = i * N;
        for (size_t j = 0; j < N; ++j) {
            int count = 0;
            if (i > 0      && input[base - N + j] == 1) ++count;
            if (i < N - 1  && input[base + N + j] == 1) ++count;
            if (j > 0      && input[base + j - 1] == 1) ++count;
            if (j < N - 1  && input[base + j + 1] == 1) ++count;
            output[base + j] = (count == 1) ? 1 : 0;
        }
    }
