   input: A=[[1, -1, 2], [0, -3, 1]] x=[2, 1, 0]
   output: y=[1, -3]   */
inline void gemv(const std::vector<double>& A,
                 const std::vector<double>& x,
                 std::vector<double>& y,
                 size_t M, size_t N)
{
    constexpr size_t BLK = 64;            // block size for cache‑friendly processing
    const double* a  = A.data();
    const double* vx = x.data();
          double* vy = y.data();

    // Zero output vector in parallel
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < M; ++i) {
        vy[i] = 0.0;
    }

    // Main blocked multiply
    #pragma omp parallel for schedule(dynamic,1) collapse(1)
    for (size_t ii = 0; ii < M; ii += BLK) {
        size_t i_max = std::min(ii + BLK, M);
        for (size_t jj = 0; jj < N; jj += BLK) {
            size_t j_max = std::min(jj + BLK, N);
            for (size_t i = ii; i < i_max; ++i) {
                double sum = vy[i];
                const double* a_row = a + i * N + jj;
                for (size_t j = jj; j < j_max; ++j) {
                    sum += a_row[j - jj] * vx[j];
                }
                vy[i] = sum;
            }
        }
    }
}
