/* Simulate one generation of Game of Life on `input`. Store the results in `output`.
   Both grids are NxN, row‑major, with values 0 or 1. */
inline void gameOfLife(const std::vector<int> &input, std::vector<int> &output, size_t N) {
    const size_t stride = N;
    const size_t total  = N * N;

    /* Parallelise the outer loop.  The workload is almost perfectly
     * load‑balanced, so static scheduling gives the best performance. */
#pragma omp parallel for schedule(static)
    for (size_t idx = 0; idx < total; ++idx) {
        const size_t i = idx / stride;
        const size_t j = idx % stride;

        // Load neighbours once to avoid repeated pointer arithmetic
        int val     = input[idx];
        int sum     = 0;
        const int *row_above = (i > 0)     ? &input[(i - 1) * stride] : nullptr;
        const int *row_below = (i < N-1)   ? &input[(i + 1) * stride] : nullptr;
        const int *row_curr  = &input[i * stride];

        /* Count live neighbours */
        if (row_above) {
            if (j > 0)     sum += row_above[j - 1];
            sum += row_above[j];
            if (j < N-1)   sum += row_above[j + 1];
        }
        if (row_curr) {
            if (j > 0)     sum += row_curr[j - 1];
            if (j < N-1)   sum += row_curr[j + 1];
        }
        if (row_below) {
            if (j > 0)     sum += row_below[j - 1];
            sum += row_below[j];
            if (j < N-1)   sum += row_below[j + 1];
        }

        /* Apply the rules */
        if (val) {
            output[idx] = (sum == 2 || sum == 3) ? 1 : 0;
        } else {
            output[idx] = (sum == 3) ? 1 : 0;
        }
    }
}
