struct Point {
    double x, y;
};

/* Convex hull (Monotone chain) – O(n log n) sorting + O(n) hull construction.
   The implementation is tuned for gcc‑O2, x86‑64, 8 threads. */
static inline double cross(const Point &a, const Point &b, const Point &c) noexcept {
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

void convexHull(const std::vector<Point> &points, std::vector<Point> &hull) {
    const std::size_t n = points.size();
    if (n < 3) { hull = points; return; }

    std::vector<Point> sorted(points);           // copy
    std::sort(sorted.begin(), sorted.end(), [](const Point &p1, const Point &p2) {
        return p1.x < p2.x || (p1.x == p2.x && p1.y < p2.y);
    });

    /* Work buffer – 2*n is sufficient for lower+upper hull.
       Reserve once to avoid reallocations. */
    std::vector<Point> buf;
    buf.reserve(2 * n);
    std::size_t k = 0;                           // current hull size

    /* Lower hull */
    for (std::size_t i = 0; i < n; ++i) {
        while (k >= 2 && cross(buf[k-2], buf[k-1], sorted[i]) <= 0) --k;
        if (k == buf.size()) buf.push_back(sorted[i]); else buf[k] = sorted[i];
        ++k;
    }

    /* Upper hull – skip last point to avoid duplicate */
    std::size_t t = k + 1;
    for (std::size_t i = n-1; i > 0; --i) {
        while (k >= t && cross(buf[k-2], buf[k-1], sorted[i-1]) <= 0) --k;
        if (k == buf.size()) buf.push_back(sorted[i-1]); else buf[k] = sorted[i-1];
        ++k;
    }

    buf.resize(k-1);      // last point equals first one
    hull = std::move(buf);
}
