#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <algorithm>
#include <cstdint>
#include <omp.h>

/*  Cooley‑Tukey radix‑2 iterative FFT.
    The function matches the original interface and produces bit‑exact
    results for the same input data.
*/
inline void fft(std::vector<std::complex<double>> const& x,
                std::vector<std::complex<double>>& output)
{
    const std::size_t N = x.size();
    output = x;                                       // copy input

    /* pre‑compute bit‑reversal table once per call */
    std::vector<std::size_t> rev(N);
    unsigned int m = static_cast<unsigned int>(std::log2(N));
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t r = i;
        r = ((r >> 1) & 0x55555555u) | ((r & 0x55555555u) << 1);
        r = ((r >> 2) & 0x33333333u) | ((r & 0x33333333u) << 2);
        r = ((r >> 4) & 0x0f0f0f0fu) | ((r & 0x0f0f0f0fu) << 4);
        r = ((r >> 8) & 0x00ff00ffu) | ((r & 0x00ff00ffu) << 8);
        r = (r >> 16) | (r << 16);
        rev[i] = r >> (32 - m);
    }

    /* in‑place butterfly stage with OpenMP parallelism */
    for (unsigned int s = 0; s < m; ++s) {
        const std::size_t step = 1u << s;
        const std::size_t half = step << 1;
        const double angle = -M_PI / step;
        const std::complex<double> wstep(std::cos(angle), std::sin(angle));

        #pragma omp parallel for schedule(static)
        for (std::size_t i = 0; i < N; i += half) {
            std::complex<double> w(1.0, 0.0);
            for (std::size_t j = 0; j < step; ++j) {
                std::size_t pos1 = i + j;
                std::size_t pos2 = pos1 + step;
                const std::complex<double> u = output[pos1];
                const std::complex<double> v = output[pos2] * w;
                output[pos1] = u + v;
                output[pos2] = u - v;
                w *= wstep;
            }
        }
    }

    /* final bit‑reversal permutation (in‑place) */
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t j = rev[i];
        if (j > i) {
            std::swap(output[i], output[j]);
        }
    }
}
