#pragma once
#include <vector>
#include <algorithm>
#include <omp.h>

struct Result {
   int startTime, duration;
   float value;
};

/*
 * Sort vector of Result structs by startTime in ascending order.
 * Implementation uses a hybrid parallel sort: for small ranges std::sort
 * is used, otherwise the range is split into chunks processed in parallel
 * and the resulting sub-vectors are merged.
 */
static inline void parallel_sort(std::vector<Result>& vec, int left, int right, int depth = 0) {
   if (right - left <= 256) {                      // threshold for std::sort
      std::sort(vec.begin() + left, vec.begin() + right,
                [](Result const& a, Result const& b){ return a.startTime < b.startTime; });
      return;
   }

   int mid = (left + right) >> 1;
   if (depth < 8) {                                 // limit recursion depth
#pragma omp task shared(vec) firstprivate(mid, left, right, depth)
      parallel_sort(vec, left, mid, depth + 1);
#pragma omp task shared(vec) firstprivate(mid, left, right, depth)
      parallel_sort(vec, mid,     right, depth + 1);
#pragma omp taskwait
   } else {
      parallel_sort(vec, left, mid, depth + 1);
      parallel_sort(vec, mid,   right, depth + 1);
   }

   std::inplace_merge(vec.begin() + left, vec.begin() + mid, vec.begin() + right,
                      [](Result const& a, Result const& b){ return a.startTime < b.startTime; });
}

inline void sortByStartTime(std::vector<Result> &results) {
   if (results.empty()) return;
#pragma omp parallel
   {
#pragma omp single
      parallel_sort(results, 0, static_cast<int>(results.size()));
   }
}
