  // Disjoint set (union‑find) with atomic operations
inline int find_root(std::vector<std::atomic<int>> &parent, int x) {
    int p = parent[x];
    while (p != x) {
        int grand = parent[p];
        if (grand != p) parent[x].store(grand, std::memory_order_relaxed); // path halving
        x = p;
        p = grand;
    }
    return x;
}

inline void unite(std::vector<std::atomic<int>> &parent,
                  std::vector<std::atomic<int>> &rank,
                  int a, int b) {
    while (true) {
        int ra = find_root(parent, a);
        int rb = find_root(parent, b);
        if (ra == rb) return;

        // Union by rank
        int rra = rank[ra];
        int rrb = rank[rb];
        if (rra < rrb) {
            if (parent[ra].compare_exchange_strong(ra, rb,
                                                   std::memory_order_acq_rel,
                                                   std::memory_order_relaxed))
                return;
        } else if (rra > rrb) {
            if (parent[rb].compare_exchange_strong(rb, ra,
                                                   std::memory_order_acq_rel,
                                                   std::memory_order_relaxed))
                return;
        } else {
            if (parent[ra].compare_exchange_strong(ra, rb,
                                                   std::memory_order_acq_rel,
                                                   std::memory_order_relaxed)) {
                rank[rb].fetch_add(1, std::memory_order_relaxed);
                return;
            }
        }
        // retry if contention
    }
}

/* Count the number of connected components in the undirected graph
   represented by the NxN adjacency matrix A (row‑major).  */
int componentCount(std::vector<int> const& A, size_t N) {
    if (N == 0) return 0;

    std::vector<std::atomic<int>> parent(N);
    std::vector<std::atomic<int>> rank(N);
    for (size_t i = 0; i < N; ++i) {
        parent[i].store(i, std::memory_order_relaxed);
        rank[i].store(0, std::memory_order_relaxed);
    }

    // Scan upper triangle of matrix; union connected vertices
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i) {
        size_t base = i * N;
        for (size_t j = i + 1; j < N; ++j) {
            if (A[base + j]) {
                unite(parent, rank, static_cast<int>(i), static_cast<int>(j));
            }
        }
    }

    // Count unique roots
    std::vector<char> seen(N, 0);
    int comps = 0;
    for (size_t i = 0; i < N; ++i) {
        int root = find_root(parent, static_cast<int>(i));
        if (!seen[root]) {
            seen[root] = 1;
            ++comps;
        }
    }
    return comps;
}
