#include <omp.h>

/* Compute one iteration of a 5-point 2D Jacobi stencil on `input`.  
 * The result is written into `output`. Boundaries are treated as zero.
 * Uses OpenMP parallelism and cache‑friendly blocking for speed. */
inline void jacobi2D(const std::vector<double> &input,
                     std::vector<double>       &output,
                     std::size_t                N)
{
    const double *in  = input.data();
    double       *out = output.data();

    /* block size tuned for cache (assumes 8‑byte doubles, L2 ~256kB) */
    constexpr std::size_t B = 64;

    #pragma omp parallel for collapse(2) schedule(static)
    for (std::size_t bi = 0; bi < N; bi += B)
    for (std::size_t bj = 0; bj < N; bj += B)
    {
        const std::size_t i_end = std::min(bi + B, N);
        const std::size_t j_end = std::min(bj + B, N);

        for (std::size_t i = bi; i < i_end; ++i)
        {
            const std::size_t iN  = i * N;
            const std::size_t ipN = (i + 1) * N;
            const std::size_t imN = (i == 0 ? iN : (i - 1) * N);

            for (std::size_t j = bj; j < j_end; ++j)
            {
                double sum = in[iN + j];

                /* up */
                if (i > 0)           sum += in[imN + j];
                /* down */
                if (i + 1 < N)       sum += in[ipN + j];
                /* left */
                if (j > 0)           sum += in[iN + j - 1];
                /* right */
                if (j + 1 < N)       sum += in[iN + j + 1];

                out[iN + j] = sum / 5.0;
            }
        }
    }
}
