/* Multiply the matrix A by the matrix B. Store the results in the matrix C.
   A is an MxK matrix, B is a KxN matrix, and C is a MxN matrix. The matrices are stored in row-major.
   Example:
   input: A=[[1, -1, 2], [0, -2, 1]] B=[[4, 1], [-1, 0], [2, 2]]
   output: C=[[9, 5], [4, 2]]
*/
inline void gemm(const std::vector<double> &A,
                 const std::vector<double> &B,
                 std::vector<double> &C,
                 size_t M, size_t K, size_t N)
{
    // Parallelise over the outer two loops – i (row) and k (inner dimension)
    // to distribute work evenly across all available threads.  The innermost
    // loop over j is left single‑threaded to preserve the original order
    // of updates to C (and thus exactly match the original behaviour).
#pragma omp parallel for collapse(2) schedule(static)
    for (size_t i = 0; i < M; ++i) {
        const double *Ai = &A[i * K];
        double *Ci     = &C[i * N];
        for (size_t k = 0; k < K; ++k) {
            double aik = Ai[k];
            const double *Bk = &B[k * N];
            // Standard naïve inner loop; let the compiler auto‑vectorise.
            for (size_t j = 0; j < N; ++j) {
                Ci[j] += aik * Bk[j];
            }
        }
    }
}
