#pragma once
#include <vector>
#include <omp.h>

/*
 * Perform in‑place LU factorisation of a square matrix A.
 * The matrix is stored in a single vector in row‑major order.
 * The algorithm is equivalent to the canonical Doolittle
 * values but is parallelised with OpenMP and SIMD directives.
 *
 *   A[i][k] = L[i][k]      (for i > k)
 *   A[k][j] = U[k][j]      (for j >= k)
 *
 * The routine does NOT pivot; the caller must ensure that
 * the matrix is non‑singular and that division by zero does
 * not occur.
 */
inline void luFactorize(std::vector<double>& A, size_t N)
{
    // Raw pointer for faster indexing
    double* a = A.data();

    // OpenMP schedule may be unrolled for compactness
    for (size_t k = 0; k < N; ++k) {
        double aik = a[k * N + k];

        // Parallelise over the rows below the pivot
        #pragma omp parallel for schedule(static) shared(a,N,k,aik) if(N > 64)
        for (size_t i = k + 1; i < N; ++i) {
            double factor = a[i * N + k] / aik;
            a[i * N + k] = factor;           // store the L element

            // Update the trailing sub‑matrix
            #pragma omp simd
            for (size_t j = k + 1; j < N; ++j) {
                a[i * N + j] -= factor * a[k * N + j];
            }
        }
    }
}
