/*
 * Compute the rank of each value in the vector `x` by sorting the indices
 * according to the corresponding values. The resulting ranks are written
 * into `ranks_`. The function is thread‑safe and does not modify `x`.
 *
 * Example:
 *  input:  [3.1, 2.8, 9.1, 0.4, 3.14]
 *  output: [2, 1, 4, 0, 3]
 *
 *  input:  [100, 7.6, 16.1, 18, 7.6]
 *  output: [4, 0, 1, 2, 3]
 */
inline void ranks(std::vector<float> const& x, std::vector<size_t> &ranks_) {
    size_t n = x.size();

    // Ensure the output vector is the correct size
    if (ranks_.size() != n) ranks_.resize(n);

    // Build an index array [0, 1, 2, ..., n-1]
    std::vector<size_t> indices(n);
    std::iota(indices.begin(), indices.end(), 0);

    // Sort the indices according to the corresponding value in x
    std::sort(indices.begin(), indices.end(),
              [&x](size_t i1, size_t i2) { return x[i1] < x[i2]; });

    // Translate the sorted position back into the rank of each element
    for (size_t i = 0; i < n; ++i) {
        ranks_[indices[i]] = i;
    }
}
