}

/* Return the perimeter of the smallest convex polygon that contains all the points. */
double convexHullPerimeter(const std::vector<Point>& points) {
    const std::size_t n = points.size();
    if (n < 3) return 0.0;

    /* Make a copy and sort it lexicographically by (x, y).  The lambda is defined
     * outside the loop to avoid repeatedly re‑creating it. */
    std::vector<Point> pts = points;
    std::sort(pts.begin(), pts.end(),
              [](const Point& a, const Point& b) {
                  return a.x < b.x || (a.x == b.x && a.y < b.y);
              });

    /* The convex hull will contain at most n points (lower + upper). */
    std::vector<Point> hull;
    hull.reserve(2 * n);

    /* Build lower hull. */
    for (const auto& p : pts) {
        while (hull.size() >= 2 &&
               cross(hull[hull.size() - 2], hull[hull.size() - 1], p) <= 0)
            hull.pop_back();
        hull.push_back(p);
    }

    /* Build upper hull.  Skip the first and last point to avoid duplication. */
    for (std::size_t i = n - 1; i > 0; --i) {
        const Point& p = pts[i - 1];
        while (hull.size() >= n + 1 &&
               cross(hull[hull.size() - 2], hull[hull.size() - 1], p) <= 0)
            hull.pop_back();
        hull.push_back(p);
    }

    /* The last point in the vector is the same as the first one; remove it. */
    hull.pop_back();

    /* Compute the perimeter.  We use a raw pointer for a single pass. */
    double perimeter = 0.0;
    const std::size_t m = hull.size();
    const Point* base = hull.data();
    for (std::size_t i = 0; i < m; ++i) {
        const Point& p1 = base[i];
        const Point& p2 = base[(i + 1) % m];
        perimeter += dist(p1, p2);
    }

    return perimeter;
}
