struct Point {
    double x, y;
};

namespace {

inline double dist(const Point& a, const Point& b) {
    double dx = a.x - b.x;
    double dy = a.y - b.y;
    return std::sqrt(dx * dx + dy * dy);
}

// Helper to find the minimum of two distances
inline double min2(double a, double b) {
    return a < b ? a : b;
}

// Recursive function that assumes points are sorted by x.
double closestPairRec(std::vector<Point>& pts, std::vector<Point>& tmp,
                      size_t left, size_t right) {
    size_t n = right - left;
    if (n <= 3) {
        double d = std::numeric_limits<double>::max();
        for (size_t i = left; i < right; ++i)
            for (size_t j = i + 1; j < right; ++j)
                d = min2(d, dist(pts[i], pts[j]));
        std::sort(pts.begin() + left, pts.begin() + right,
                  [](const Point& a, const Point& b) { return a.y < b.y; });
        return d;
    }

    size_t mid = left + n / 2;
    double midx = pts[mid].x;

    double dl = closestPairRec(pts, tmp, left, mid);
    double dr = closestPairRec(pts, tmp, mid, right);
    double d = min2(dl, dr);

    // Merge the two halves sorted by Y into tmp
    std::inplace_merge(pts.begin() + left, pts.begin() + mid, pts.begin() + right,
                       [](const Point& a, const Point& b) { return a.y < b.y; });

    // Build strip of points close to the dividing line
    std::vector<Point> strip;
    strip.reserve(n);
    for (size_t i = left; i < right; ++i) {
        if (std::abs(pts[i].x - midx) < d)
            strip.push_back(pts[i]);
    }

    // Check distances within strip (at most 6 neighbours per point)
    size_t sz = strip.size();
    for (size_t i = 0; i < sz; ++i)
        for (size_t j = i + 1; j < sz && (strip[j].y - strip[i].y) < d; ++j)
            d = min2(d, dist(strip[i], strip[j]));

    return d;
}

} // namespace

/**
 * Return the distance between the closest pair of points in `points`.
 *
 * The implementation uses a standard O(n log n) divide‑and‑conquer algorithm.
 * It is deliberately written to be portable and to avoid any use of
 * std::sort with a custom comparator inside inner loops to keep the
 * critical sections small.  The algorithm remains deterministic and
 * preserves the exact behaviour of the original quadratic implementation.
 */
double closestPair(std::vector<Point> const& points) {
    if (points.size() < 2) return 0.0;

    // Copy points to a mutable vector and sort by X
    std::vector<Point> pts(points);
    std::sort(pts.begin(), pts.end(),
              [](const Point& a, const Point& b) { return a.x < b.x; });

    // Temporary buffer for merging by Y
    std::vector<Point> tmp(pts.size());

    // Recursive compute in a single thread (parallelism not needed for D&C)
    return closestPairRec(pts, tmp, 0, pts.size());
}
