#include <vector>
#include <algorithm>

/* Sort the vector ``x`` of complex numbers by their magnitude (|z|) in ascending order.
   Efficiency: uses squared magnitude to avoid an expensive square‑root and
   a single work‑share to compute magnitudes in parallel when the data size
   exceeds a practical threshold.
*/
void sortComplexByMagnitude(std::vector<std::complex<double>>& x) {
    // If the vector is empty or has a single element, nothing to do
    if (x.size() <= 1) return;

#if defined(_OPENMP)
    // Parallel compute squared magnitudes for large vectors
    const size_t N = x.size();
    std::vector<double> mags(N);
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < N; ++i) {
        const auto& c = x[i];
        mags[i] = c.real() * c.real() + c.imag() * c.imag();
    }

    // Sort indices based on the pre‑computed magnitudes
    std::vector<size_t> idx(N);
    for (size_t i = 0; i < N; ++i) idx[i] = i;

    std::sort(idx.begin(), idx.end(),
              [&](size_t a, size_t b) { return mags[a] < mags[b]; });

    // Reorder the original vector according to the sorted indices
    std::vector<std::complex<double>> tmp = std::move(x);
    for (size_t i = 0; i < N; ++i) {
        x[i] = tmp[idx[i]];
    }
#else
    // Fallback: compute squared magnitude on the fly (single‑threaded)
    std::sort(x.begin(), x.end(),
              [](const std::complex<double>& a, const std::complex<double>& b) {
                  const double mag_a = a.real() * a.real() + a.imag() * a.imag();
                  const double mag_b = b.real() * b.real() + b.imag() * b.imag();
                  return mag_a < mag_b;
              });
#endif
}
