#include <omp.h>

#ifndef M_PI
#define M_PI 3.14159265358979323846264338327950288
#endif

// Fast radix‑2 Cooley‑Tukey FFT (in‑place, power‑of‑two size)
// The function implements the same algorithm as the reference
// but uses pre‑computed twiddle factors and parallel loops.
inline void fft_helper(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();
    const std::size_t logN = static_cast<std::size_t>(std::log2(N));

    // --- pre‑compute twiddle factors (reuse between stages) -------------
    std::vector<std::complex<double>> W(logN);
    for (std::size_t s = 0; s < logN; ++s) {
        const std::size_t m = 1ULL << s;
        const double theta = -M_PI / m;            // negative for forward FFT
        const double c = std::cos(theta);
        const double s_ = std::sin(theta);
        W[s] = std::complex<double>(c, s_);
    }

    // --- bit‑reversal permutation ---------------------------------------
    std::vector<std::size_t> rev(N);
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t x = i;
        std::size_t y = 0;
        for (std::size_t j = 0; j < logN; ++j) {
            y = (y << 1) | (x & 1);
            x >>= 1;
        }
        rev[i] = y;
    }
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        if (rev[i] > i) std::swap(x[i], x[rev[i]]);
    }

    // --- main butterfly stages ------------------------------------------
    for (std::size_t s = 0; s < logN; ++s) {
        const std::size_t m = 1ULL << s;
        const std::complex<double> wm = W[s];
        const std::size_t step = 2 * m;

        // Parallel over the groups in this stage
        #pragma omp parallel for schedule(static)
        for (std::size_t k = 0; k < m; ++k) {
            std::complex<double> w = 1.0;
            for (std::size_t j = k; j < N; j += step) {
                std::complex<double> t = w * x[j + m];
                std::complex<double> u = x[j];
                x[j]        = u + t;
                x[j + m]    = u - t;
                w *= wm;
            }
        }
    }
}

// Inverse FFT using the conjugate‑and‑forward trick
inline void ifft(std::vector<std::complex<double>>& x)
{
    // Conjugate the input
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < x.size(); ++i)
        x[i] = std::conj(x[i]);

    // Forward FFT
    fft_helper(x);

    // Conjugate again and scale
    const double invN = 1.0 / static_cast<double>(x.size());
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < x.size(); ++i)
        x[i] = std::conj(x[i]) * invN;
}
