#pragma once
#include <vector>
#include <complex>
#include <cstddef>
#include <cmath>
#include <thread>
#include <algorithm>

namespace detail {
    // Pre‑compute twiddle factors for a given fft size
    inline void precompute_twiddles(std::vector<std::complex<double>>& w, std::size_t N) {
        w.resize(N / 2);
        const double PI = 3.141592653589793238462643383279502884L;
        for (std::size_t k = 0; k < N / 2; ++k) {
            double angle = -2.0 * PI * static_cast<double>(k) / static_cast<double>(N);
            w[k] = std::exp(std::complex<double>(0, angle));
        }
    }

    // Bit‑reverse indices up to the nearest power of two
    inline void compute_bitrev(std::vector<std::size_t>& rev, std::size_t N, std::size_t m) {
        rev.resize(N);
        for (std::size_t i = 0; i < N; ++i) {
            std::size_t v = i;
            std::size_t r = 0;
            for (std::size_t j = 0; j < m; ++j) {
                r = (r << 1) | (v & 1);
                v >>= 1;
            }
            rev[i] = r;
        }
    }
}

// In‑place radix‑2 Cooley‑Tukey FFT (conventional, no bit‑rev on the fly)
inline void fftRadix2(std::vector<std::complex<double>>& x) {
    const std::size_t N = x.size();

    // --------------------------------------------------------------------
    //   1) Bit‑reverse permutation
    // --------------------------------------------------------------------
    std::size_t m = 0;
    for (std::size_t tmp = N; tmp > 1; tmp >>= 1) ++m;
    std::vector<std::size_t> rev;
    detail::compute_bitrev(rev, N, m);
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t j = rev[i];
        if (j > i) std::swap(x[i], x[j]);
    }

    // --------------------------------------------------------------------
    //   2) Swift butterfly passes (interleaved calculation)
    // --------------------------------------------------------------------
    std::vector<std::complex<double>> w;
    detail::precompute_twiddles(w, N);

    for (std::size_t s = 1; s <= m; ++s) {
        std::size_t m2 = 1 << s;          // size of sub‑FFT
        std::size_t half = m2 >> 1;       // stride for the butterfly
        std::size_t step = N / m2;        // twiddle step

        // Parallelise over the outer loop (fastest varying index) safely
        #pragma omp parallel for schedule(static)
        for (std::size_t k = 0; k < N; k += m2) {
            std::size_t idx = 0;
            for (std::size_t j = 0; j < half; ++j, ++idx) {
                std::size_t in = k + j;
                std::size_t out = in + half;
                std::complex<double> t = w[idx * step] * x[out];
                x[out] = x[in] - t;
                x[in] += t;
            }
        }
    }
}

// ------------------------------------------------------------------------
//   Public API – exactly the same as in the original header
// ------------------------------------------------------------------------
inline void fftConjugate(std::vector<std::complex<double>>& x) {
    // 1) FFT
    fftRadix2(x);

    // 2) point‑wise conjugation
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < x.size(); ++i) {
        x[i] = std::conj(x[i]);
    }
}
