inline void sortIgnoreZero(std::vector<int> &x) {
    const std::size_t n = x.size();
    if (n == 0) return;

    // Collect non‑zero values and their original positions.
    std::vector<int> nonZero;
    std::vector<std::size_t> indices;
    nonZero.reserve(n);
    indices.reserve(n);

    for (std::size_t i = 0; i < n; ++i) {
        const int v = x[i];
        if (v != 0) {
            nonZero.push_back(v);
            indices.push_back(i);
        }
    }

    if (nonZero.empty()) return;  // nothing to sort

    // Sort the extracted non‑zero values.
    std::sort(nonZero.begin(), nonZero.end());

    // Write the sorted values back to the original positions.
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < indices.size(); ++i) {
        x[indices[i]] = nonZero[i];
    }
