/* Edge-detection kernel (3x3). */
constexpr int edgeKernel[3][3] = {
    {-1, -1, -1},
    {-1,  8, -1},
    {-1, -1, -1}
};

/*
   Convolves the `edgeKernel` with a square grayscale image.
   The image is stored in row-major order. Pixels outside the original
   bounds are treated as zero. The result is clipped to [0, 255].
   Parameters:
     - imageIn  : input image (N x N)
     - imageOut : output image (N x N, must be pre-sized)
     - N        : image dimension
   The function is fully parallelized with OpenMP.
*/
inline void convolveKernel(std::vector<int> const& imageIn,
                           std::vector<int> &imageOut,
                           size_t N)
{
    /* Create a padded image [0 .. N+1][0 .. N+1] to remove boundary checks. */
    const size_t padded = N + 2;
    std::vector<int> paddedImage(padded * padded, 0);

    /* Copy original image into the padded buffer at offset (1,1). */
    for (size_t i = 0; i < N; ++i) {
        std::copy_n(&imageIn[i * N], N, &paddedImage[(i + 1) * padded + 1]);
    }

    /* Local alias for easier access. */
    const int* restrict pad = paddedImage.data();
    int* restrict out = imageOut.data();
    constexpr int kSize = 3;

    /* Parallel per-row processing. */
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i)
    {
        const size_t baseRow = (i + 1) * padded;          // row in padded image
        const size_t outRow = i * N;                     // row in output image
        for (size_t j = 0; j < N; ++j)
        {
            /* Manual unrolling of the 3x3 kernel. */
            int sum = 0;
            const int* restrict row0 = pad + baseRow - padded;      // i-1
            const int* restrict row1 = pad + baseRow;              // i
            const int* restrict row2 = pad + baseRow + padded;      // i+1

            /* Column offsets: j-1, j, j+1 */
            sum += row0[j]     * edgeKernel[0][0];
            sum += row0[j + 1] * edgeKernel[0][1];
            sum += row0[j + 2] * edgeKernel[0][2];

            sum += row1[j]     * edgeKernel[1][0];
            sum += row1[j + 1] * edgeKernel[1][1];
            sum += row1[j + 2] * edgeKernel[1][2];

            sum += row2[j]     * edgeKernel[2][0];
            sum += row2[j + 1] * edgeKernel[2][1];
            sum += row2[j + 2] * edgeKernel[2][2];

            /* Clamp to [0,255] manually. */
            out[outRow + j] = static_cast<int>( std::max(0, std::min(255, sum)) );
        }
    }
}
