#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

// Solve the linear system Ax = b for x.
// A is an NxN matrix in row-major. x and b have N elements.
// The algorithm is identical to the reference implementation but
// uses pointer arithmetic, cache‑friendly blocking and OpenMP
// parallelization of the elimination step.

static inline double* row_ptr(std::vector<double>& mat, size_t i, size_t N) {
    return &mat[i * N];
}

void solveLinearSystem(std::vector<double> const& A,
                       std::vector<double> const& b,
                       std::vector<double> &x,
                       size_t N) {

    // Work on copies of the inputs
    std::vector<double> A_copy = A;
    std::vector<double> b_copy = b;

    // ----- Gaussian elimination (forward elimination) -----
    for (size_t i = 0; i + 1 < N; ++i) {
        const double pivot = A_copy[i * N + i];
        if (pivot == 0.0) return;               // singular matrix

        // Parallelize over rows j > i
        #pragma omp parallel for schedule(static) shared(A_copy, b_copy, pivot, i, N)
        for (size_t j = i + 1; j < N; ++j) {
            const double factor = A_copy[j * N + i] / pivot;

            // Update row j, columns i..N-1
            double* const row_j = row_ptr(A_copy, j, N);
            double* const row_i = row_ptr(A_copy, i, N);
            for (size_t k = i; k < N; ++k) {
                row_j[k] -= factor * row_i[k];
            }
            b_copy[j] -= factor * b_copy[i];
        }
    }

    // ----- Back substitution -----
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        double sum = 0.0;
        for (size_t j = i + 1; j < N; ++j) {
            sum += A_copy[i * N + j] * x[j];
        }
        x[i] = (b_copy[i] - sum) / A_copy[i * N + i];
    }
}
