#pragma once
#include <vector>
#include <cmath>
#include <limits>
#include <omp.h>

/* Return the index of the value in the vector x that is closest to the math constant PI.
   Use M_PI for the value of PI.
   Example:
   input: [9.18, 3.05, 7.24, 11.3, -166.49, 2.1]
   output: 1
*/
size_t findClosestToPi(std::vector<double> const& x) {
    const double pi = M_PI;
    size_t bestIdx = 0;
    double bestDiff = std::numeric_limits<double>::infinity();

    // OpenMP parallel search with simple reduction pattern
    #pragma omp parallel
    {
        size_t localIdx = 0;
        double localDiff = std::numeric_limits<double>::infinity();
        int rank = omp_get_thread_num();
        int nthreads = omp_get_num_threads();

        // Stride loop: each thread handles a subset of indices
        for (size_t i = rank; i < x.size(); i += nthreads) {
            double diff = std::abs(x[i] - pi);
            if (diff < localDiff) {
                localDiff = diff;
                localIdx = i;
            }
        }

        // Single critical section to combine local minima
        #pragma omp critical
        {
            if (localDiff < bestDiff) {
                bestDiff = localDiff;
                bestIdx = localIdx;
            }
        }
    }

    return bestIdx;
}
